// ---------------------------------------------------------------------
//  100% client-side search (GitHub Pages compatible).
//  Loads /search.json (generated by Jekyll) and filters by title,
//  content, categories and tags. No external dependencies.
// ---------------------------------------------------------------------
(function () {
  var input = document.getElementById('search-input');
  var results = document.getElementById('search-results');
  var status = document.getElementById('search-status');
  if (!input || !results) return;

  var data = [];
  var ready = false;

  // Read ?q= from the URL for searches coming from the sidebar.
  function getQueryParam() {
    var m = window.location.search.match(/[?&]q=([^&]+)/);
    return m ? decodeURIComponent(m[1].replace(/\+/g, ' ')) : '';
  }

  function normalize(s) {
    return (s || '')
      .toLowerCase()
      .normalize('NFD')
      .replace(/[̀-ͯ]/g, ''); // strip accents
  }

  function render(items, q) {
    results.innerHTML = '';
    if (!q) { status.textContent = ''; return; }
    if (items.length === 0) {
      status.textContent = 'No results for “' + q + '”.';
      return;
    }
    status.textContent = items.length + ' result(s) for “' + q + '”.';
    items.forEach(function (it) {
      var li = document.createElement('li');
      li.innerHTML =
        '<a class="result-title" href="' + it.url + '">' + it.title + '</a>' +
        '<div class="result-meta">' + (it.date || '') +
        (it.category ? ' · ' + it.category : '') + '</div>' +
        '<p>' + it.snippet + '</p>';
      results.appendChild(li);
    });
  }

  function search(q) {
    var nq = normalize(q.trim());
    if (!ready || !nq) { render([], q.trim()); return; }
    var terms = nq.split(/\s+/);
    var matched = data.filter(function (it) {
      return terms.every(function (t) { return it._index.indexOf(t) !== -1; });
    }).slice(0, 50);
    render(matched, q.trim());
  }

  fetch(input.getAttribute('data-index') || '/search.json')
    .then(function (r) { return r.json(); })
    .then(function (json) {
      data = json.map(function (it) {
        it._index = normalize(
          it.title + ' ' + it.content + ' ' + it.category + ' ' + it.tags
        );
        it.snippet = (it.content || '').slice(0, 160) + '…';
        return it;
      });
      ready = true;
      var initial = getQueryParam();
      if (initial) { input.value = initial; search(initial); }
    })
    .catch(function () {
      if (status) status.textContent = 'Could not load the search index.';
    });

  var t;
  input.addEventListener('input', function () {
    clearTimeout(t);
    var v = input.value;
    t = setTimeout(function () { search(v); }, 120);
  });
})();
